function solve(n, edges) {
    // DSU setup
    const parent = Array(n).fill(0).map((_, i) => i);
    // dist[i] stores the XOR distance (parity) from node i to its current parent.
    const dist = Array(n).fill(0);

    /**
     * Find operation with path compression and distance update.
     * Returns [root, distance_to_root]
     */
    const find = (i) => {
        if (parent[i] === i) {
            return [i, 0];
        }

        // Recurse to find the true root R and the distance d(parent[i], R)
        const [root, d_parent_to_root] = find(parent[i]);

        // Update distance[i]: d(i, R) = d(i, parent[i]) XOR d(parent[i], R)
        dist[i] = dist[i] ^ d_parent_to_root;

        // Path compression
        parent[i] = root;

        return [root, dist[i]];
    };

    let acceptedEdgesCount = 0;

    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const w = edge[2];

        // 1. Find roots and distances from nodes to their roots
        const [rootU, d_u] = find(u);
        const [rootV, d_v] = find(v);

        if (rootU !== rootV) {
            // Case 1: Different components. Accept the edge and union the sets.

            // Merge rootU into rootV's set (Arbitrary union direction).
            parent[rootU] = rootV;

            // Calculate the new distance for rootU: d(rootU, rootV)
            // Path: rootU --(d_u)--> u --(w)--> v --(d_v)--> rootV
            // d(rootU, rootV) = d(rootU, u) XOR d(u, v) XOR d(v, rootV)
            // d(rootU, u) = d_u (since XOR is its own inverse)
            // d(v, rootV) = d_v

            dist[rootU] = d_u ^ w ^ d_v;

            acceptedEdgesCount++;

        } else {
            // Case 2: Same component. A cycle is formed. Check for cycle parity constraint.

            // Existing path distance between u and v is d_u XOR d_v.
            // The new cycle weight is (d_u XOR d_v) XOR w.
            if ((d_u ^ d_v ^ w) === 0) {
                // Condition met: cycle has even weight. Accept the edge.
                acceptedEdgesCount++;
            } else {
                // Condition failed: cycle has odd weight. Reject the edge.
            }
        }
    }

    return acceptedEdgesCount;
}

