            // Merge rootU into rootV's set (arbitrarily choosing V as the new root/representative).
            parent[rootU] = rootV;

            // Calculate the new distance for rootU: d(rootU, rootV)
            // Path: rootU --(d_u)--> u --(w)--> v --(d_v)--> rootV
