        public int[] find(int i) {
            if (parent[i] == i) {
                return new int[]{i, 0};
            }

            // Recurse to find the true root R and the distance d(parent[i], R)
            int[] resultParent = find(parent[i]);
            int root = resultParent[0];
            int d_parent_to_root = resultParent[1];

            // Update distance[i]: d(i, R) = d(i, parent[i]) XOR d(parent[i], R)
            dist[i] = dist[i] ^ d_parent_to_root;

            // Path compression
