    // Helper class to encapsulate DSU logic with parity tracking
    private static class DSU {
        int[] parent;
        int[] dist; // XOR distance to parent (0 or 1)

        DSU(int N) {
            parent = new int[N];
            dist = new int[N];
            for (int i = 0; i < N; i++) {
                parent[i] = i;
                dist[i] = 0;
            }
        }

        // Returns {root, distance_to_root}
        // Uses recursion for path compression
        int[] find(int i) {
            if (parent[i] == i) {
                return new int[]{i, 0};
            }

            // Recurse to find the true root R and the distance d(parent[i], R)
            int[] result = find(parent[i]);
            int root = result[0];
            int d_parent_to_root = result[1];

            // Update distance[i]: d(i, R) = d(i, parent[i]) XOR d(parent[i], R)
            dist[i] = dist[i] ^ d_parent_to_root;

            // Path compression
            parent[i] = root;

            return new int[]{root, dist[i]};
        }
    }

